package tools.jackson.core;

import java.util.Objects;

/**
 * Default implementation of {@link TypeIdentifierWriter} that provides
 * standard logic for writing type identifiers.
 *
 * @since 3.0
 */
public class DefaultTypeIdentifierWriter implements TypeIdentifierWriter {

    /**
     * Singleton instance of the default writer.
     */
    public static final DefaultTypeIdentifierWriter instance = new DefaultTypeIdentifierWriter();

    protected DefaultTypeIdentifierWriter() { }

    @Override
    public WritableTypeId writeTypePrefix(JsonGenerator g, WritableTypeId typeIdDef)
        throws JacksonException
    {
        final boolean wasStartObjectWritten = g.canWriteTypeId()
                ? _writeTypePrefixUsingNative(g, typeIdDef)
                : _writeTypePrefixUsingWrapper(g, typeIdDef);

        // And then possible start marker for value itself:
        switch (typeIdDef.valueShape) {
        case START_OBJECT:
            if (!wasStartObjectWritten) {
                g.writeStartObject(typeIdDef.forValue);
            }
            break;
        case START_ARRAY:
            g.writeStartArray(typeIdDef.forValue);
            break;
        default: // otherwise: no start marker
        }

        return typeIdDef;
    }

    @Override
    public WritableTypeId writeTypeSuffix(JsonGenerator g, WritableTypeId typeIdDef) throws JacksonException
    {
        final JsonToken valueShape = typeIdDef.valueShape;
        // First: does value need closing?
        if (valueShape == JsonToken.START_OBJECT) {
            g.writeEndObject();
        } else if (valueShape == JsonToken.START_ARRAY) {
            g.writeEndArray();
        }

        if (typeIdDef.wrapperWritten) {
            switch (typeIdDef.include) {
            case WRAPPER_ARRAY:
                g.writeEndArray();
                break;
            case PARENT_PROPERTY:
                // unusually, need to output AFTER value. And no real wrapper...
                {
                    Object id = typeIdDef.id;
                    String idStr = (id instanceof String) ? (String) id : String.valueOf(id);
                    g.writeStringProperty(typeIdDef.asProperty, idStr);
                }
                break;
            case METADATA_PROPERTY:
            case PAYLOAD_PROPERTY:
                // no actual wrapper; included within Object itself
                break;
            case WRAPPER_OBJECT:
            default: // should never occur but...
                g.writeEndObject();
                break;
            }
        }
        return typeIdDef;
    }

    protected boolean _writeTypePrefixUsingNative(JsonGenerator g, WritableTypeId typeIdDef) throws JacksonException {
        typeIdDef.wrapperWritten = false;
        g.writeTypeId(typeIdDef.id);
        return false;
    }

    protected boolean _writeTypePrefixUsingWrapper(JsonGenerator g, WritableTypeId typeIdDef) throws JacksonException {
        // Normally we only support String type ids (non-String reserved for native type ids)
        final String id = Objects.toString(typeIdDef.id, null);

        // If we don't have Type ID we don't write a wrapper.
        if (id == null) {
            return false;
        }
        WritableTypeId.Inclusion incl = typeIdDef.include;

        // first: cannot output "as property" if value not Object; if so, must do "as array"
        if ((typeIdDef.valueShape != JsonToken.START_OBJECT) && incl.requiresObjectContext()) {
            typeIdDef.include = incl = WritableTypeId.Inclusion.WRAPPER_ARRAY;
        }

        typeIdDef.wrapperWritten = true;
        switch (incl) {
        case PARENT_PROPERTY:
            // nothing to do here, as it has to be written in suffix...
            break;
        case PAYLOAD_PROPERTY:
            // only output as native type id; otherwise caller must handle using some
            // other mechanism, so...
            break;
        case METADATA_PROPERTY:
            // must have Object context by now, so simply write as field name
            // Note, too, that it's bit tricky, since we must print START_OBJECT that is part
            // of value first -- and then NOT output it later on: hence return "early"
            g.writeStartObject(typeIdDef.forValue);
            g.writeStringProperty(typeIdDef.asProperty, id);
            return true;

        case WRAPPER_OBJECT:
            // NOTE: this is wrapper, not directly related to value to output, so
            // do NOT pass "typeIdDef.forValue"
            g.writeStartObject();
            g.writeName(id);
            break;
        case WRAPPER_ARRAY:
        default: // should never occur but translate as "as-array"
            g.writeStartArray(); // wrapper, not actual array object to write
            g.writeString(id);
        }
        return false;
    }
}
